text:
@each $name, $theme in $zones {
  .#{config.$prefix}--#{'' + $name} {
    background-color: custom-property.get-var('background');
    color: custom-property.get-var('text-primary');

    @each $key, $value in $theme {
      @if $key == 'color-scheme' {
        @include custom-property.declaration($key, $value);

        color-scheme: custom-property.get-var($key, $value);
      } @else if meta.type-of($value) == color {
        @include custom-property.declaration($key, $value);
      }
    }

    // Note: we need to re-emit the contextual layer tokens as part of the theme
    // mixin. Otherwise, the layer tokens are defined at the :root level and will
    // not pick up the theme-specific, or zone-specific, value from the first
    // layer.
    //
    // @see https://github.com/carbon-design-system/carbon/issues/11138
    @include layer-tokens.emit-layer-tokens(1);

    @each $group in $-components {
      @each $key, $value in $group {
        @if meta.type-of($value) == map {
          $fallback: map.get($value, fallback);
          $theme-values: map.get($value, values);

          @each $theme-value in $theme-values {
            $value: map.get($theme-value, value);

            @if theme.matches(map.get($theme-value, theme), $theme) and
              meta.type-of($value) ==
              color
            {
              @include custom-property.declaration($key, $value);
            }
          }
        } @else if meta.type-of($value) == color {
          @include custom-property.declaration($key, $value);
        }
      }
    }
  }
}

@layer components {
  .AccordionWebsiteRoot {
    border-top: 1px solid var(--gray-t2);
  }

  .AccordionWebsiteItem {
    box-sizing: border-box;
    border-bottom: 1px solid var(--gray-t2);
  }

  .AccordionWebsiteHeader {
    margin: 0;
  }

  .AccordionWebsiteTrigger {
    box-sizing: border-box;
    position: relative;
    display: flex;
    width: 100%;
    gap: 1rem;
    align-items: center;
    justify-content: space-between;
    color: inherit;
    font-family: inherit;
    background-color: transparent;
    font-size: 1rem;
    padding-block: 0.75rem;
    padding-inline: 0;
    line-height: 1.5rem;
    border: none;
    outline: none;
    text-align: left;
    -webkit-tap-highlight-color: transparent;
  }

  .AccordionWebsiteTrigger:focus-visible {
    outline: 2px solid currentColor;
  }

  .AccordionWebsiteIconMinus {
    display: none;
  }

  .AccordionWebsiteIconPlus {
    display: block;
  }

  .AccordionWebsiteTrigger[data-panel-open] .AccordionWebsiteIconPlus {
    display: none;
  }

  .AccordionWebsiteTrigger[data-panel-open] .AccordionWebsiteIconMinus {
    display: block;
  }

  .AccordionWebsitePanel {
    padding-block-start: 4px;
    padding-block-end: 12px;
  }
}

body {
  font-family:
    -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen, Ubuntu,
    Cantarell, "Open Sans", "Helvetica Neue", sans-serif;
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 100vh;
  margin: 0;
  background-color: #f5f5f5;
  padding: 20px;
}

label {
  font-weight: bold;
  display: block;
  margin-bottom: 5px;
}

input[type="text"] {
  border: 1px solid #ccc;
  padding: 10px;
  font-size: 16px;
  width: 100%;
  box-sizing: border-box;
  margin-bottom: 10px;
  border-radius: 4px;
  outline-offset: 4px;
}

button {
  background-color: black;
  border-radius: 4px;
  color: white;
  padding: 10px 24px;
  border: none;
  cursor: pointer;
  width: 100%;
  font-size: 16px;
  outline-offset: 4px;
}

button:hover {
  opacity: 0.8;
}

button[aria-disabled="true"] {
  opacity: 0.5;
  cursor: not-allowed;
}

ul {
  padding: 0;
  margin: auto;
}

li {
  background: #f9f9f9;
  padding: 10px;
  margin-bottom: 10px;
  border: 1px solid #ddd;
  border-radius: 4px;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border-width: 0;
}

@mixin dialog($enable-presence: false) {
  .#{$prefix}--dialog {
    position: fixed;
    padding: 0;
    border: none;
    margin: auto;
    background-color: $layer;
    color: $text-primary;
    inline-size: 48rem;
    inset: 0;
    max-block-size: 100%;

    @include breakpoint(md) {
      max-inline-size: 84%;
    }
    @include breakpoint(lg) {
      max-inline-size: 60%;
    }
    @include breakpoint(xlg) {
      max-inline-size: 48%;
    }

    @if not(enabled('enable-presence') or $enable-presence) {
      opacity: 0;
      transform: translateY(calc(-1 * #{$spacing-06}));
      transition:
        opacity $duration-moderate-02 motion(exit, expressive),
        transform $duration-moderate-02 motion(exit, expressive),
        overlay $duration-moderate-02 motion(exit, expressive) allow-discrete,
        display $duration-moderate-02 motion(exit, expressive) allow-discrete;

      @media (prefers-reduced-motion) {
        transition: none;
      }

      &[open] {
        opacity: 1;
        transform: translateY(0);

        transition:
          opacity $duration-moderate-02 motion(entrance, expressive),
          transform $duration-moderate-02 motion(entrance, expressive),
          overlay
            $duration-moderate-02
            motion(entrance, expressive)
            allow-discrete,
          display
            $duration-moderate-02
            motion(entrance, expressive)
            allow-discrete;

        @media (prefers-reduced-motion) {
          transition: none;
        }
      }
    }
  }
}
